#include<bits/stdc++.h>
using namespace std;
long long dfn[100010],fa[100010],d[100010],siz[100010],son[100010],top[100010],dfncnt,val[100010],rnk[100010];
vector<long long> mp[100010];
void dfs1(long long x,long long f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            fa[i]=x;
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(long long i:mp[x])
        {
            if(i!=son[x]&&i!=fa[x])
            {
                dfs2(i,i);
            }
        }
    }
}
struct segment_tree
{
    struct node
    {
        long long l,r,sum,lazy;
    }a[500010];
    void init(long long x,long long l,long long r)
    {
        long long mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum=0;
            return;
        }
        init(x<<1,l,mid);
        init(x<<1|1,mid+1,r);
        a[x].sum+=a[x<<1].sum;
        a[x].sum+=a[x<<1|1].sum;
    }
    void update(long long x,long long l,long long r,long long z)
    {
        if(l<=a[x].l&&a[x].r<=r)
        {
            a[x].lazy+=z;
            a[x].sum+=(a[x].r-a[x].l+1)*z;
            return;
        }
        long long mid=(a[x].l+a[x].r)>>1;
        a[x<<1].lazy+=a[x].lazy;
        a[x<<1|1].lazy+=a[x].lazy;
        a[x<<1].sum+=a[x].lazy*(a[x<<1].r-a[x<<1].l+1);
        a[x<<1|1].sum+=a[x].lazy*(a[x<<1|1].r-a[x<<1|1].l+1);
        a[x].lazy=0;
        if(l<=mid)
        {
            update(x<<1,l,r,z);
        }
        if(r>mid)
        {
            update(x<<1|1,l,r,z);
        }
        a[x].sum=a[x<<1].sum;
        a[x].sum+=a[x<<1|1].sum;
    }
    long long getsum(long long x,long long l,long long r)
    {
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum;
        }
        long long mid=(a[x].l+a[x].r)/2,ans=0;
        a[x<<1].lazy+=a[x].lazy;
        a[x<<1|1].lazy+=a[x].lazy;
        a[x<<1].sum+=a[x].lazy*(a[x<<1].r-a[x<<1].l+1);
        a[x<<1|1].sum+=a[x].lazy*(a[x<<1|1].r-a[x<<1|1].l+1);
        a[x].lazy=0;
        if(l<=mid)
        {
            ans=getsum(x<<1,l,r);
        }
        if(r>mid)
        {
            ans+=getsum(x<<1|1,l,r);
        }
        return ans;
    }
}t;
void add(long long x,long long y,long long z)
{
    long long tx=top[x],ty=top[y];
    while(tx!=ty)
    {
        if(d[tx]>=d[ty])
        {
            t.update(1,dfn[tx],dfn[x],z);
            x=fa[tx];
        }
        else
        {
            t.update(1,dfn[ty],dfn[y],z);
            y=fa[ty];
        }
        tx=top[x];
        ty=top[y];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    t.update(1,dfn[x],dfn[y],z);
}
int main()
{
    long long n;
    scanf("%lld",&n);
    for(long long i=1;i<n;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        x++,y++;
        mp[x].push_back(y);
        mp[y].push_back(x);
    }
    dfs1(1);
    dfs2(1,1);
    t.init(1,1,n);
    long long q;
    scanf("%lld",&q);
    while(q--)
    {
        char ch=getchar();
        long long x,y,z;
        while(!isalpha(ch))
        {
            ch=getchar();
        }
        if(ch=='A')
        {
            scanf("%lld%lld%lld",&x,&y,&z);
            x++;
            y++;
            add(x,y,z);
        }
        else
        {
            scanf("%lld",&x);
            x++;
            printf("%lld\n",t.getsum(1,dfn[x],dfn[x]+siz[x]-1));
        }
    }
    return 0;
}
